// Get shop data from Shop Lookup node
const shop = $node['Shop Lookup by DID'].json[0] || $node['Shop Lookup by DID'].json;
const caller = $node['Caller Lookup'].json[0] || null;
const callerPhone = $node['Retell Pre-Call Webhook'].json.body.from_number || '';

// Determine current day/time in shop timezone
const now = new Date();
// In production, use luxon or moment-timezone with shop.timezone
const days = ['sunday','monday','tuesday','wednesday','thursday','friday','saturday'];
const dayName = days[now.getDay()];
const hoursJson = typeof shop.hours_json === 'string' ? JSON.parse(shop.hours_json) : shop.hours_json;
const todayHours = hoursJson[dayName];

// Format hours string
let hoursToday = 'Closed today';
let shopIsOpen = 'false';

if (todayHours && todayHours.open && todayHours.close) {
  const formatTime = (t) => {
    const [h, m] = t.split(':').map(Number);
    const ampm = h >= 12 ? 'PM' : 'AM';
    const h12 = h % 12 || 12;
    return `${h12}:${m.toString().padStart(2, '0')} ${ampm}`;
  };
  hoursToday = `Open today ${formatTime(todayHours.open)} – ${formatTime(todayHours.close)}`;

  // Check if currently open (simplified — use timezone-aware logic in production)
  const currentHHMM = now.toTimeString().slice(0, 5);
  if (currentHHMM >= todayHours.open && currentHHMM < todayHours.close) {
    shopIsOpen = 'true';
  }
}

const transferAvailable = (shopIsOpen === 'true' && shop.transfer_number) ? 'true' : 'false';
const customerName = (caller && caller.name) ? caller.name : '';
const returningCustomer = (caller && caller.name) ? 'yes' : 'no';

return {
  json: {
    dynamic_variables: {
      shop_name: shop.name || '',
      address: shop.address || '',
      hours_today: hoursToday,
      diag_fee: shop.diag_fee_text || '',
      services: shop.services_text || '',
      makes_serviced: shop.makes_serviced_text || '',
      tow_policy: shop.tow_policy_text || '',
      customer_name: customerName,
      caller_phone: callerPhone,
      returning_customer: returningCustomer,
      shop_is_open: shopIsOpen,
      transfer_available: transferAvailable,
      transfer_number: shop.transfer_number || ''
    },
    override_agent_id: null
  }
};
